import React, { useState, useEffect } from 'react';
import { supabase } from './supabase';

function getNegocioId() {
  const params = new URLSearchParams(window.location.search);
  return params.get('negocio');
}

export default function App() {
  const [negocio, setNegocio] = useState(null);
  const [productos, setProductos] = useState([]);
  const [carrito, setCarrito] = useState([]);
  const [pantalla, setPantalla] = useState('catalogo');
  const [cargando, setCargando] = useState(true);
  const [enviando, setEnviando] = useState(false);
  const [error, setError] = useState('');
  const [form, setForm] = useState({ nombre:'', telefono:'', direccion:'', nota:'', tipoEntrega:'delivery' });
  const [obteniendo, setObteniendo] = useState(false);
  const [productoDetalle, setProductoDetalle] = useState(null);
  const negocioId = getNegocioId();

  useEffect(() => {
    if (!negocioId) { setCargando(false); return; }
    const cargar = async () => {
      const { data: neg } = await supabase.from('negocios').select('*').eq('id', negocioId).single();
      const { data: prods } = await supabase.from('productos').select('*').eq('negocio_id', negocioId).eq('activo', true);
      setNegocio(neg);
      setProductos(prods || []);
      setCargando(false);
    };
    cargar();
  }, [negocioId]);

  const agregarAlCarrito = (prod) => {
    setCarrito(prev => {
      const existe = prev.find(x => x.id === prod.id);
      if (existe) return prev.map(x => x.id===prod.id ? {...x, cant: x.cant+1} : x);
      return [...prev, { ...prod, cant: 1 }];
    });
    setProductoDetalle(null);
  };

  const cambiarCant = (id, delta) => {
    setCarrito(prev => prev.map(x => x.id===id ? {...x, cant: x.cant+delta} : x).filter(x => x.cant > 0));
  };

  const obtenerUbicacion = () => {
    if (!navigator.geolocation) { setError('Tu navegador no soporta GPS'); return; }
    setObteniendo(true);
    navigator.geolocation.getCurrentPosition(
      (pos) => {
        const { latitude, longitude } = pos.coords;
        const link = `https://maps.google.com/?q=${latitude},${longitude}`;
        setForm(prev => ({ ...prev, direccion: link, gps: { lat: latitude, lng: longitude } }));
        setObteniendo(false);
      },
      () => { setError('No se pudo obtener ubicación. Escríbela manualmente.'); setObteniendo(false); }
    );
  };

  const total = carrito.reduce((s,x) => s + x.cant*x.precio, 0);
  const delivery = form.tipoEntrega === 'delivery' ? 15 : 0;
  const totalFinal = total + delivery;
  const cantTotal = carrito.reduce((s,x) => s + x.cant, 0);

  const confirmarPedido = async () => {
    if (!form.nombre || !form.telefono) { setError('Por favor llena tu nombre y teléfono'); return; }
    if (form.tipoEntrega === 'delivery' && !form.direccion) { setError('Por favor ingresa tu dirección o comparte tu ubicación'); return; }
    setEnviando(true); setError('');
    const { error } = await supabase.from('pedidos').insert({
      negocio_id: negocioId,
      cliente_nombre: form.nombre,
      cliente_telefono: form.telefono,
      cliente_direccion: form.tipoEntrega === 'delivery' ? form.direccion : '🏪 Recoge en local',
      productos: carrito.map(x => ({ nombre: x.nombre, cant: x.cant, precio: x.precio })),
      total: totalFinal,
      estado: 'nuevo',
      nota: `${form.tipoEntrega === 'recoger' ? '🏪 RECOGER EN LOCAL' : '🚚 DELIVERY'}${form.nota ? ' | ' + form.nota : ''}`
    });
    if (error) { setError('Error al enviar. Intenta de nuevo.'); setEnviando(false); return; }
    setEnviando(false);
    setPantalla('confirmado');
  };

  if (!negocioId) return (
    <div style={{ minHeight:'100vh', background:'linear-gradient(135deg,#2563EB,#7C3AED)', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:16, padding:'2rem' }}>
      <div style={{ fontSize:64 }}>🛍</div>
      <div style={{ fontSize:24, fontWeight:800, color:'#fff' }}>PedidosFácil</div>
      <div style={{ fontSize:15, color:'rgba(255,255,255,0.8)', textAlign:'center', maxWidth:300 }}>Accede al link que te compartió el negocio para hacer tu pedido.</div>
    </div>
  );

  if (cargando) return (
    <div style={{ minHeight:'100vh', background:'linear-gradient(135deg,#2563EB,#7C3AED)', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:16 }}>
      <div style={{ fontSize:48 }}>🛍</div>
      <div style={{ fontSize:15, color:'rgba(255,255,255,0.9)' }}>Cargando menú...</div>
    </div>
  );

  if (!negocio) return (
    <div style={{ minHeight:'100vh', display:'flex', alignItems:'center', justifyContent:'center', flexDirection:'column', gap:12 }}>
      <div style={{ fontSize:48 }}>😕</div>
      <div style={{ fontSize:16, fontWeight:600 }}>Negocio no encontrado</div>
    </div>
  );

  if (pantalla === 'confirmado') return (
    <div style={{ minHeight:'100vh', background:'linear-gradient(135deg,#10B981,#059669)', display:'flex', alignItems:'center', justifyContent:'center', padding:'1rem' }}>
      <div style={{ background:'#fff', borderRadius:24, padding:'2.5rem', textAlign:'center', maxWidth:380, width:'100%', boxShadow:'0 20px 60px rgba(0,0,0,0.15)' }}>
        <div style={{ width:80, height:80, borderRadius:'50%', background:'#F0FDF4', display:'flex', alignItems:'center', justifyContent:'center', margin:'0 auto 1rem', fontSize:40 }}>✅</div>
        <div style={{ fontSize:24, fontWeight:800, marginBottom:8 }}>¡Pedido enviado!</div>
        <div style={{ fontSize:15, color:'#64748B', marginBottom:16 }}>
          <strong>{negocio.nombre}</strong> recibió tu pedido y te contactará al <strong>{form.telefono}</strong>
        </div>
        <div style={{ background: form.tipoEntrega==='delivery'?'#EFF6FF':'#F0FDF4', borderRadius:12, padding:'12px', marginBottom:16, fontSize:14, fontWeight:600, color: form.tipoEntrega==='delivery'?'#2563EB':'#10B981' }}>
          {form.tipoEntrega === 'delivery' ? '🚚 Tu pedido llegará a tu dirección' : '🏪 Pasa a recoger al local'}
        </div>
        <div style={{ background:'#F8FAFC', borderRadius:14, padding:'1rem', marginBottom:24, textAlign:'left' }}>
          {carrito.map((x,i) => (
            <div key={i} style={{ display:'flex', justifyContent:'space-between', fontSize:14, marginBottom:6, alignItems:'center' }}>
              <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                {x.foto_url && <img src={x.foto_url} alt={x.nombre} style={{ width:28, height:28, borderRadius:6, objectFit:'cover' }} />}
                <span>{x.cant}x {x.nombre}</span>
              </div>
              <span style={{ fontWeight:600 }}>Bs. {x.cant*x.precio}</span>
            </div>
          ))}
          {delivery > 0 && <div style={{ display:'flex', justifyContent:'space-between', fontSize:13, color:'#94A3B8', marginTop:4 }}><span>Delivery</span><span>Bs. {delivery}</span></div>}
          <div style={{ borderTop:'1px solid #E2E8F0', marginTop:10, paddingTop:10, display:'flex', justifyContent:'space-between', fontWeight:800, fontSize:16 }}>
            <span>Total pagado</span><span style={{ color:'#10B981' }}>Bs. {totalFinal}</span>
          </div>
        </div>
        <button onClick={()=>{ setCarrito([]); setForm({nombre:'',telefono:'',direccion:'',nota:'',tipoEntrega:'delivery'}); setPantalla('catalogo'); }}
          style={{ width:'100%', padding:'14px', borderRadius:12, border:'none', background:'linear-gradient(135deg,#2563EB,#7C3AED)', color:'#fff', fontWeight:700, fontSize:16, cursor:'pointer' }}>
          Hacer otro pedido
        </button>
      </div>
    </div>
  );

  return (
    <div style={{ maxWidth:480, margin:'0 auto', minHeight:'100vh', background:'#F8FAFC' }}>

      {/* Header bonito */}
      <div style={{ background:'linear-gradient(135deg,#2563EB,#7C3AED)', color:'#fff', padding:'1.5rem 1rem 2.5rem', position:'relative' }}>
        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
          <div>
            <div style={{ fontWeight:800, fontSize:22 }}>{negocio.nombre}</div>
            <div style={{ fontSize:13, opacity:0.8, marginTop:2 }}>🏪 {negocio.tipo} · Pedidos online</div>
          </div>
          {pantalla !== 'catalogo' && (
            <button onClick={()=>setPantalla(pantalla==='datos'?'carrito':'catalogo')}
              style={{ background:'rgba(255,255,255,0.2)', color:'#fff', border:'none', borderRadius:10, padding:'8px 14px', cursor:'pointer', fontSize:14, fontWeight:600, backdropFilter:'blur(10px)' }}>
              ← Volver
            </button>
          )}
          {pantalla==='catalogo' && carrito.length > 0 && (
            <button onClick={()=>setPantalla('carrito')}
              style={{ background:'#fff', color:'#2563EB', border:'none', borderRadius:99, padding:'10px 18px', fontWeight:800, cursor:'pointer', fontSize:14, boxShadow:'0 4px 12px rgba(0,0,0,0.15)' }}>
              🛒 {cantTotal} · Bs. {total}
            </button>
          )}
        </div>
      </div>

      {/* MODAL detalle producto */}
      {productoDetalle && (
        <div style={{ position:'fixed', inset:0, background:'rgba(0,0,0,0.6)', zIndex:100, display:'flex', alignItems:'flex-end', justifyContent:'center' }}
          onClick={e=>{ if(e.target===e.currentTarget) setProductoDetalle(null); }}>
          <div style={{ background:'#fff', borderRadius:'24px 24px 0 0', width:'100%', maxWidth:480, padding:'1.5rem', paddingBottom:'2rem' }}>
            {productoDetalle.foto_url && (
              <img src={productoDetalle.foto_url} alt={productoDetalle.nombre}
                style={{ width:'100%', height:220, objectFit:'cover', borderRadius:16, marginBottom:'1rem' }} />
            )}
            <div style={{ fontSize:22, fontWeight:800, marginBottom:4 }}>{productoDetalle.nombre}</div>
            <div style={{ fontSize:14, color:'#64748B', marginBottom:8 }}>{productoDetalle.categoria}</div>
            <div style={{ fontSize:24, fontWeight:800, color:'#2563EB', marginBottom:'1.5rem' }}>Bs. {productoDetalle.precio}</div>
            <div style={{ display:'flex', gap:10 }}>
              <button onClick={()=>setProductoDetalle(null)}
                style={{ flex:1, padding:'14px', borderRadius:12, border:'1px solid #E2E8F0', background:'#fff', fontWeight:600, cursor:'pointer', fontSize:15 }}>
                Cerrar
              </button>
              <button onClick={()=>agregarAlCarrito(productoDetalle)}
                style={{ flex:2, padding:'14px', borderRadius:12, border:'none', background:'linear-gradient(135deg,#2563EB,#7C3AED)', color:'#fff', fontWeight:700, cursor:'pointer', fontSize:15 }}>
                + Agregar al carrito
              </button>
            </div>
          </div>
        </div>
      )}

      {/* CATÁLOGO */}
      {pantalla==='catalogo' && (
        <div style={{ padding:'1rem', marginTop:'-1rem' }}>
          {productos.length === 0 ? (
            <div style={{ textAlign:'center', padding:'4rem 2rem', color:'#94A3B8' }}>
              <div style={{ fontSize:48, marginBottom:12 }}>😔</div>
              <div style={{ fontWeight:700, fontSize:16 }}>No hay productos disponibles</div>
            </div>
          ) : (
            <>
              <div style={{ fontSize:13, color:'#64748B', marginBottom:'1rem', fontWeight:500 }}>{productos.length} productos disponibles</div>
              <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:12 }}>
                {productos.map(prod => {
                  const enCarrito = carrito.find(x=>x.id===prod.id);
                  return (
                    <div key={prod.id} style={{ background:'#fff', borderRadius:16, overflow:'hidden', boxShadow:'0 2px 12px rgba(0,0,0,0.06)', cursor:'pointer' }}
                      onClick={()=>setProductoDetalle(prod)}>
                      {prod.foto_url ? (
                        <img src={prod.foto_url} alt={prod.nombre} style={{ width:'100%', height:130, objectFit:'cover' }} />
                      ) : (
                        <div style={{ width:'100%', height:130, background:'linear-gradient(135deg,#EFF6FF,#F5F3FF)', display:'flex', alignItems:'center', justifyContent:'center', fontSize:48 }}>
                          {prod.emoji||'📦'}
                        </div>
                      )}
                      <div style={{ padding:'10px 12px 12px' }}>
                        <div style={{ fontWeight:700, fontSize:14, marginBottom:2, color:'#1E293B' }}>{prod.nombre}</div>
                        <div style={{ fontSize:12, color:'#94A3B8', marginBottom:8 }}>{prod.categoria}</div>
                        <div style={{ display:'flex', alignItems:'center', justifyContent:'space-between' }}>
                          <div style={{ fontWeight:800, color:'#2563EB', fontSize:16 }}>Bs. {prod.precio}</div>
                          {enCarrito ? (
                            <div style={{ display:'flex', alignItems:'center', gap:6 }} onClick={e=>e.stopPropagation()}>
                              <button onClick={()=>cambiarCant(prod.id,-1)}
                                style={{ width:26, height:26, borderRadius:'50%', border:'2px solid #2563EB', background:'#fff', color:'#2563EB', fontSize:16, cursor:'pointer', fontWeight:800, display:'flex', alignItems:'center', justifyContent:'center' }}>−</button>
                              <span style={{ fontWeight:800, fontSize:14, minWidth:16, textAlign:'center', color:'#1E293B' }}>{enCarrito.cant}</span>
                              <button onClick={()=>cambiarCant(prod.id,1)}
                                style={{ width:26, height:26, borderRadius:'50%', border:'none', background:'#2563EB', color:'#fff', fontSize:16, cursor:'pointer', fontWeight:800, display:'flex', alignItems:'center', justifyContent:'center' }}>+</button>
                            </div>
                          ) : (
                            <button onClick={e=>{ e.stopPropagation(); agregarAlCarrito(prod); }}
                              style={{ width:32, height:32, borderRadius:'50%', border:'none', background:'linear-gradient(135deg,#2563EB,#7C3AED)', color:'#fff', fontSize:20, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', fontWeight:700, boxShadow:'0 2px 8px rgba(37,99,235,0.4)' }}>+</button>
                          )}
                        </div>
                      </div>
                    </div>
                  );
                })}
              </div>
            </>
          )}

          {carrito.length > 0 && (
            <div style={{ position:'sticky', bottom:16, marginTop:'1.5rem' }}>
              <button onClick={()=>setPantalla('carrito')}
                style={{ width:'100%', padding:'16px', borderRadius:16, border:'none', background:'linear-gradient(135deg,#2563EB,#7C3AED)', color:'#fff', fontWeight:800, fontSize:16, cursor:'pointer', boxShadow:'0 8px 24px rgba(37,99,235,0.4)' }}>
                🛒 Ver carrito · {cantTotal} items · Bs. {total}
              </button>
            </div>
          )}
        </div>
      )}

      {/* CARRITO */}
      {pantalla==='carrito' && (
        <div style={{ padding:'1rem' }}>
          <div style={{ fontWeight:800, fontSize:18, marginBottom:'1rem', color:'#1E293B' }}>Tu carrito 🛒</div>
          <div style={{ display:'flex', flexDirection:'column', gap:10, marginBottom:'1.25rem' }}>
            {carrito.map(x => (
              <div key={x.id} style={{ display:'flex', alignItems:'center', gap:12, background:'#fff', borderRadius:16, padding:'12px 14px', boxShadow:'0 2px 8px rgba(0,0,0,0.05)' }}>
                {x.foto_url ? (
                  <img src={x.foto_url} alt={x.nombre} style={{ width:52, height:52, borderRadius:10, objectFit:'cover', flexShrink:0 }} />
                ) : (
                  <div style={{ width:52, height:52, borderRadius:10, background:'#F1F5F9', display:'flex', alignItems:'center', justifyContent:'center', fontSize:28, flexShrink:0 }}>{x.emoji||'📦'}</div>
                )}
                <div style={{ flex:1 }}>
                  <div style={{ fontWeight:700, fontSize:14, color:'#1E293B' }}>{x.nombre}</div>
                  <div style={{ fontSize:13, color:'#2563EB', fontWeight:600 }}>Bs. {x.precio} c/u</div>
                </div>
                <div style={{ display:'flex', alignItems:'center', gap:8 }}>
                  <button onClick={()=>cambiarCant(x.id,-1)} style={{ width:30, height:30, borderRadius:'50%', border:'2px solid #E2E8F0', background:'#fff', fontSize:16, cursor:'pointer', fontWeight:700, display:'flex', alignItems:'center', justifyContent:'center' }}>−</button>
                  <span style={{ fontWeight:800, fontSize:15, minWidth:18, textAlign:'center' }}>{x.cant}</span>
                  <button onClick={()=>cambiarCant(x.id,1)} style={{ width:30, height:30, borderRadius:'50%', border:'none', background:'#2563EB', color:'#fff', fontSize:16, cursor:'pointer', fontWeight:700, display:'flex', alignItems:'center', justifyContent:'center' }}>+</button>
                </div>
                <div style={{ fontWeight:800, fontSize:15, minWidth:64, textAlign:'right', color:'#1E293B' }}>Bs. {x.cant*x.precio}</div>
              </div>
            ))}
          </div>

          {/* Tipo entrega */}
          <div style={{ marginBottom:'1.25rem' }}>
            <div style={{ fontWeight:700, fontSize:15, marginBottom:10, color:'#1E293B' }}>¿Cómo quieres recibirlo?</div>
            <div style={{ display:'grid', gridTemplateColumns:'1fr 1fr', gap:10 }}>
              {[
                { key:'delivery', icon:'🚚', label:'Delivery', sub:'+Bs. 15', color:'#2563EB', bg:'#EFF6FF' },
                { key:'recoger', icon:'🏪', label:'Recoger', sub:'Sin costo', color:'#10B981', bg:'#F0FDF4' },
              ].map(op => (
                <button key={op.key} onClick={()=>setForm(prev=>({...prev, tipoEntrega:op.key, direccion: op.key==='recoger'?'Recoge en local':'', gps:null}))}
                  style={{ padding:'16px 12px', borderRadius:14, border:`2px solid ${form.tipoEntrega===op.key?op.color:'#E2E8F0'}`,
                    background: form.tipoEntrega===op.key?op.bg:'#fff', cursor:'pointer', textAlign:'center', transition:'all 0.15s' }}>
                  <div style={{ fontSize:32, marginBottom:6 }}>{op.icon}</div>
                  <div style={{ fontWeight:700, fontSize:15, color: form.tipoEntrega===op.key?op.color:'#1E293B' }}>{op.label}</div>
                  <div style={{ fontSize:12, color:'#64748B', marginTop:2 }}>{op.sub}</div>
                </button>
              ))}
            </div>
          </div>

          <div style={{ background:'#fff', borderRadius:16, padding:'1rem', marginBottom:'1.25rem', boxShadow:'0 2px 8px rgba(0,0,0,0.05)' }}>
            <div style={{ display:'flex', justifyContent:'space-between', fontSize:14, marginBottom:6, color:'#64748B' }}><span>Subtotal</span><span>Bs. {total}</span></div>
            {form.tipoEntrega === 'delivery' && (
              <div style={{ display:'flex', justifyContent:'space-between', fontSize:14, marginBottom:6, color:'#64748B' }}><span>Delivery</span><span>Bs. 15</span></div>
            )}
            <div style={{ display:'flex', justifyContent:'space-between', fontWeight:800, fontSize:18, borderTop:'1px solid #F1F5F9', paddingTop:10, marginTop:4 }}>
              <span>Total</span><span style={{ color:'#2563EB' }}>Bs. {totalFinal}</span>
            </div>
          </div>

          <button onClick={()=>setPantalla('datos')}
            style={{ width:'100%', padding:'16px', borderRadius:14, border:'none', background:'linear-gradient(135deg,#2563EB,#7C3AED)', color:'#fff', fontWeight:800, fontSize:16, cursor:'pointer', boxShadow:'0 8px 24px rgba(37,99,235,0.3)' }}>
            Continuar → Mis datos
          </button>
        </div>
      )}

      {/* DATOS */}
      {pantalla==='datos' && (
        <div style={{ padding:'1rem' }}>
          <div style={{ fontWeight:800, fontSize:18, marginBottom:4, color:'#1E293B' }}>
            {form.tipoEntrega === 'delivery' ? '🚚 ¿A dónde te enviamos?' : '🏪 Tus datos para recoger'}
          </div>
          <div style={{ fontSize:14, color:'#94A3B8', marginBottom:'1.5rem' }}>Total a pagar: <strong style={{ color:'#2563EB', fontSize:16 }}>Bs. {totalFinal}</strong></div>

          {[
            { key:'nombre', label:'Tu nombre completo', placeholder:'Ej: Juan Pérez', type:'text' },
            { key:'telefono', label:'Teléfono / WhatsApp', placeholder:'Ej: 71234567', type:'tel' },
          ].map(f => (
            <div key={f.key} style={{ marginBottom:'1rem' }}>
              <label style={{ fontSize:13, fontWeight:600, color:'#64748B', display:'block', marginBottom:6 }}>{f.label} <span style={{ color:'#EF4444' }}>*</span></label>
              <input value={form[f.key]} onChange={e=>setForm({...form,[f.key]:e.target.value})}
                placeholder={f.placeholder} type={f.type}
                style={{ width:'100%', padding:'14px', borderRadius:12, border:'1.5px solid #E2E8F0', fontSize:15, outline:'none', transition:'border 0.15s' }}
                onFocus={e=>e.target.style.borderColor='#2563EB'} onBlur={e=>e.target.style.borderColor='#E2E8F0'} />
            </div>
          ))}

          {form.tipoEntrega === 'delivery' && (
            <div style={{ marginBottom:'1rem' }}>
              <label style={{ fontSize:13, fontWeight:600, color:'#64748B', display:'block', marginBottom:6 }}>Dirección de entrega <span style={{ color:'#EF4444' }}>*</span></label>
              <input value={form.gps ? '📍 Ubicación GPS compartida' : form.direccion}
                onChange={e=>setForm({...form,direccion:e.target.value,gps:null})}
                placeholder="Ej: Av. Montes 345, piso 2"
                style={{ width:'100%', padding:'14px', borderRadius:12, border:'1.5px solid #E2E8F0', fontSize:15, outline:'none', marginBottom:8 }} />
              <button onClick={obtenerUbicacion} disabled={obteniendo}
                style={{ width:'100%', padding:'14px', borderRadius:12, border:'2px solid #2563EB', background: form.gps?'#EFF6FF':obteniendo?'#F8FAFC':'#fff',
                  color:'#2563EB', fontWeight:700, fontSize:14, cursor:'pointer', display:'flex', alignItems:'center', justifyContent:'center', gap:8 }}>
                {obteniendo ? '📡 Obteniendo ubicación...' : form.gps ? '✅ Ubicación GPS capturada' : '📍 Compartir mi ubicación GPS'}
              </button>
            </div>
          )}

          <div style={{ marginBottom:'1.5rem' }}>
            <label style={{ fontSize:13, fontWeight:600, color:'#64748B', display:'block', marginBottom:6 }}>Nota para el negocio (opcional)</label>
            <textarea value={form.nota} onChange={e=>setForm({...form,nota:e.target.value})}
              placeholder="Ej: Sin cebolla, tocar timbre, apartamento 3B..." rows={2}
              style={{ width:'100%', padding:'14px', borderRadius:12, border:'1.5px solid #E2E8F0', fontSize:14, outline:'none', resize:'none' }} />
          </div>

          {error && (
            <div style={{ background:'#FEF2F2', color:'#DC2626', padding:'12px 14px', borderRadius:10, fontSize:14, marginBottom:'1rem', fontWeight:500 }}>
              ⚠️ {error}
            </div>
          )}

          <button onClick={confirmarPedido} disabled={enviando}
            style={{ width:'100%', padding:'16px', borderRadius:14, border:'none',
              background: enviando ? '#93C5FD' : 'linear-gradient(135deg,#2563EB,#7C3AED)',
              color:'#fff', fontWeight:800, fontSize:16, cursor: enviando?'not-allowed':'pointer',
              boxShadow: enviando?'none':'0 8px 24px rgba(37,99,235,0.3)' }}>
            {enviando ? '⏳ Enviando pedido...' : `✅ Confirmar pedido · Bs. ${totalFinal}`}
          </button>

          <div style={{ textAlign:'center', fontSize:12, color:'#94A3B8', marginTop:'1rem' }}>
            🔒 Tu pedido es seguro · El negocio te contactará pronto
          </div>
        </div>
      )}
    </div>
  );
}
